    highest_rt_prio: Option<u8>,
    rt_nr_running: usize,
    cfs_tasks: BTreeMap<CfsKey, Arc<TaskControlBlock>>,
    cfs_nr_running: usize,
    cfs_load: u64,
    min_vruntime_ns: u64,
