            highest_rt_prio: None,
            rt_nr_running: 0,
            cfs_tasks: BTreeMap::new(),
            cfs_nr_running: 0,
            cfs_load: 0,
            min_vruntime_ns: 0,
            stop_task: None,
        }
    }

