}

impl InodeKey {
    /// 构造某个文件系统范围内的最小 key。
    pub const fn fs_range_start(fs_id: u64) -> Self {
        Self { fs_id, ino: 0 }
    }

    /// 构造某个文件系统范围内的最大 key。
