        .map(|pipe| pipe.write_peer_closed())
        .unwrap_or(false)
        || desc
            .as_any()
            .downcast_ref::<UnixSocketPairEnd>()
            .map(|socket| socket.write_peer_closed())
            .unwrap_or(false)
}

