    fn root_ppn(token: AddressSpaceToken) -> usize {
        token >> PPN_SHIFT
    }

    unsafe fn activate_token(token: AddressSpaceToken) {
        asm!(
            "dbar 0",
            "csrwr {pgd}, {pgdl}",
            "csrwr $zero, {asid}",
            "invtlb 0x00, $zero, $zero",
            "ibar 0",
            pgd = in(reg) token,
            pgdl = const CSR_PGDL,
            asid = const CSR_ASID,
