fn handle_user_oom(path: &str, access: &str, fault_addr: usize) -> ! {
    let cx = current_trap_cx();
    let summary = cx.fault_dump_summary();
    error!(
        "[kernel] fatal lazy-fault OOM: path={}, access={}, pid={}, fault_addr={:#x}, user_pc={:#x}, {}={:#x}, {}={:#x}, {}={:#x}, {}={:#x}, {}={:#x}, {}={:#x}",
