        summary[4].name,
        summary[4].value,
        summary[5].name,
        summary[5].value,
        summary[6].name,
        summary[6].value,
    );
    crate::mm::log_oom(path, Some(access), Some(fault_addr));
    exit_group_current_and_run_next(ExitReason::Signal(SignalNum::SIGKILL.number() as u32));
